import React, { useEffect, useRef } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import ParticlesBackground from "./ParticlesBackground";

const HeroSection = ({ coupleData }) => {
  const ref = useRef(null);
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start start", "end start"] });
  const y = useTransform(scrollYProgress, [0, 1], ["0%", "40%"]);
  const opacity = useTransform(scrollYProgress, [0, 0.8], [1, 0]);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.3, delayChildren: 0.5 },
    },
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 60 },
    visible: { opacity: 1, y: 0, transition: { duration: 1, ease: [0.23, 1, 0.32, 1] } },
  };

  const nameVariants = {
    hidden: { opacity: 0, scale: 0.7 },
    visible: { opacity: 1, scale: 1, transition: { duration: 1.2, ease: [0.23, 1, 0.32, 1] } },
  };

  return (
    <section
      ref={ref}
      className="relative min-h-screen flex items-center justify-center overflow-hidden"
      style={{ background: "linear-gradient(180deg, #0d0000 0%, #3d0000 40%, #1a0a0a 100%)" }}
    >
      <ParticlesBackground />

      {/* Animated radial glow */}
      <motion.div
        className="absolute inset-0 z-0"
        animate={{ opacity: [0.3, 0.6, 0.3] }}
        transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        style={{
          background: "radial-gradient(ellipse at center, rgba(139,0,0,0.4) 0%, transparent 70%)",
        }}
      />

      {/* Floating ornamental rings */}
      {[...Array(3)].map((_, i) => (
        <motion.div
          key={i}
          className="absolute rounded-full border border-gold/20"
          style={{
            width: `${300 + i * 150}px`,
            height: `${300 + i * 150}px`,
            top: "50%",
            left: "50%",
            transform: "translate(-50%, -50%)",
          }}
          animate={{ rotate: i % 2 === 0 ? 360 : -360, opacity: [0.1, 0.3, 0.1] }}
          transition={{ duration: 20 + i * 5, repeat: Infinity, ease: "linear" }}
        />
      ))}

      <motion.div
        style={{ y, opacity }}
        className="relative z-10 text-center px-4 max-w-4xl mx-auto"
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        {/* Top ornament */}
        <motion.div variants={itemVariants} className="mb-6">
          <span className="ornament">✦ ✦ ✦</span>
        </motion.div>

        <motion.p
          variants={itemVariants}
          className="font-sans text-gold/80 tracking-[0.4em] uppercase text-sm mb-4"
        >
          With Joy & Love, We Invite You To
        </motion.p>

        {/* Couple Names */}
        <motion.div variants={nameVariants} className="mb-4">
          <h1 className="font-serif text-6xl md:text-8xl lg:text-9xl font-bold leading-none">
            <span className="gold-text">{coupleData.person1}</span>
          </h1>
          <motion.div
            className="flex items-center justify-center gap-4 my-3"
            animate={{ scale: [1, 1.1, 1] }}
            transition={{ duration: 2, repeat: Infinity }}
          >
            <div className="h-px w-16 bg-gradient-to-r from-transparent to-gold" />
            <span className="text-gold text-3xl">💍</span>
            <div className="h-px w-16 bg-gradient-to-l from-transparent to-gold" />
          </motion.div>
          <h1 className="font-serif text-6xl md:text-8xl lg:text-9xl font-bold leading-none">
            <span className="gold-text">{coupleData.person2}</span>
          </h1>
        </motion.div>

        <motion.div variants={itemVariants} className="section-divider my-6" />

        <motion.p
          variants={itemVariants}
          className="font-serif italic text-beige/80 text-xl md:text-2xl mb-2"
        >
          Engagement Ceremony
        </motion.p>

        <motion.p
          variants={itemVariants}
          className="font-body text-gold tracking-widest text-lg md:text-xl font-light"
        >
          {coupleData.engagementDate}
        </motion.p>

        <motion.div variants={itemVariants} className="mt-10">
        <motion.a
            href="https://www.google.com/maps/dir//Hotel+Tamizh+Grand,+No.302%2F8-B,+Vallalar+St,+Venkata+Nagar,+Puducherry,+605011/@11.9434998,79.8184677,15z"
            target="_blank"
            rel="noopener noreferrer"
            className="btn-gold inline-block rounded-sm"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            📍 Get Location
          </motion.a>
        </motion.div>

        {/* Scroll indicator */}
        <motion.div
          variants={itemVariants}
          className="mt-16 flex flex-col items-center gap-2"
          animate={{ y: [0, 10, 0] }}
          transition={{ duration: 2, repeat: Infinity }}
        >
          <span className="text-gold/50 text-xs tracking-widest uppercase">Scroll</span>
          <div className="w-px h-12 bg-gradient-to-b from-gold/50 to-transparent" />
        </motion.div>
      </motion.div>
    </section>
  );
};

export default HeroSection;
